INSERT OR REPLACE INTO directives (id, org, deleted, version, updated_at, data) VALUES ('dir_mr6bkkpf_13', 'omega-1', 0, 1, '2026-06-22T12:09:25.971Z', '{"id":"dir_mr6bkkpf_13","ref":"O1-SO-001","org":"omega-1","clearance":"CL3","title":"Standing Orders — Field Conduct","body":"All Omega-1 operatives maintain weapons-tight posture until a containment breach is confirmed by the deployment lead. After-action reports are filed within twelve hours of return to site. Deviation is recorded as a strike.","issuedBy":"O1-1","status":"active","createdAt":"2026-06-22T12:09:25.971Z","updatedAt":"2026-06-22T12:09:25.971Z","version":1,"deleted":false,"deletedAt":null,"compartment":"cmp_mr6bkkpf_1w"}');
INSERT OR REPLACE INTO directives (id, org, deleted, version, updated_at, data) VALUES ('dir_mr6bkkpf_14', 'ethics-committee', 0, 1, '2026-06-14T12:09:25.971Z', '{"id":"dir_mr6bkkpf_14","ref":"EC-DIR-014","org":"ethics-committee","clearance":"CL4-J","title":"Containment Ethics Review Protocol","body":"Any containment procedure resulting in Class-D attrition above threshold is referred to the Committee for review within five working days. Reviewing members recuse themselves from cases involving their own prior rulings.","issuedBy":"EC-1","status":"active","createdAt":"2026-06-14T12:09:25.971Z","updatedAt":"2026-06-14T12:09:25.971Z","version":1,"deleted":false,"deletedAt":null}');
INSERT OR REPLACE INTO directives (id, org, deleted, version, updated_at, data) VALUES ('dir_mr6bkkpf_15', 'command', 0, 1, '2026-06-04T12:09:25.971Z', '{"id":"dir_mr6bkkpf_15","ref":"CMD-DIR-001","org":"command","clearance":"CL3","title":"CAIRO Access & Clearance Policy","body":"Access to CAIRO is granted on a need-to-know basis. Clearance is assigned by Command and may not be self-amended. Registrations require CL5 approval before activation. Credentials are personal and non-transferable.","issuedBy":"CMD-1","status":"active","createdAt":"2026-06-04T12:09:25.971Z","updatedAt":"2026-06-04T12:09:25.971Z","version":1,"deleted":false,"deletedAt":null}');

