INSERT OR REPLACE INTO subjects (id, org, deleted, version, updated_at, data) VALUES ('sub_mr6bkkpf_16', 'omega-1', 0, 1, '2026-06-08T12:09:25.971Z', '{"id":"sub_mr6bkkpf_16","ref":"POI-2207","alias":"Cassette","realName":"[UNIDENTIFIED]","kind":"poi","org":"omega-1","threat":"moderate","clearance":"CL3","status":"active","summary":"Suspected courier moving anomalous media between two unaffiliated groups of interest. Non-hostile to date; observe and map contacts.","lastKnownLocation":"Metro corridor, Sector 12","logs":[{"id":"log_mr6bkkpf_17","ts":"2026-06-08T12:09:25.971Z","by":"O1-1","type":"intel","text":"Watch opened following recovered handoff footage."},{"id":"log_mr6bkkpf_18","ts":"2026-06-23T12:09:25.971Z","by":"O1-7","type":"sighting","text":"Observed at transit hub; met one unidentified contact for under two minutes."},{"id":"log_mr6bkkpf_19","ts":"2026-07-01T12:09:25.971Z","by":"O1-1","type":"note","text":"Pattern suggests weekly cadence. Maintain passive watch."}],"createdBy":"O1-1","createdAt":"2026-06-08T12:09:25.971Z","updatedAt":"2026-06-08T12:09:25.971Z","version":1,"deleted":false,"deletedAt":null}');
